mapper.select:
SELECT d.id, d.devicename AS name, d.datatablename, d.id_device_type, dt.name AS device_type_name, s.id AS id_site, s.name AS site_name, t.value AS timezone_value, JSON_ARRAYAGG(JSON_OBJECT( 'name', TRIM(dp.slug), 'unit', IFNULL(dp.unit, ""), 'rounding_decimals', dp.rounding_decimals, 'aggregate_function', dp.value_chart_tool )) AS parameters FROM api_access aa JOIN api_access_site_map am ON am.id_api_access = aa.id JOIN api_access_endpoint_map em ON em.id_api_access = aa.id JOIN api_endpoint ae ON ae.id = em.id_end_point JOIN site s ON s.id = am.id_site JOIN device d ON d.id_site = s.id JOIN device_type dt ON dt.id = d.id_device_type JOIN time_zone t ON t.id = s.id_time_zone JOIN device_group dg ON d.id_device_group = dg.id JOIN device_parameters dp ON dp.id_device_group = dg.id LEFT JOIN generic_parameters gp ON gp.id = dp.id_generic_parameter WHERE aa.security_key = #{key} AND aa.status = 1 AND am.status = 1 AND em.status = 1 AND ae.route = #{route} AND ae.method = #{method} AND ae.is_active = 1 AND ae.is_delete = 0 AND s.status = 1 AND s.is_delete = 0 AND d.status = 1 AND d.is_delete = 0 AND dp.status = 1 AND dp.is_delete = 0 AND dp.is_filter = 1 AND d.show_on_domain != 6
AND IN (
#{name}
)
#{item}
AND d.id IN (${id_device})
AND (CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', t.value) < s.expiration OR s.expiration IS NULL) GROUP BY d.id

SELECT site_name, device_type_name AS type, JSON_ARRAYAGG(JSON_OBJECT( 'time', time, 'value', energy )) AS energyJSON FROM ( SELECT id_site, site_name, id_device_type, device_type_name, time_group_by AS time, CAST(SUM(energy) AS DECIMAL(10,1)) AS energy FROM (
SELECT #{item.id_site} AS id_site, #{item.site_name} AS site_name, #{item.id_device_type} AS id_device_type, #{item.device_type_name} AS device_type_name, (
) AS energy, FROM_UNIXTIME(( UNIX_TIMESTAMP(CONVERT_TZ(time, 'UTC', #{item.timezone_value})) DIV 900 )* 900, '%Y-%m-%d %H:%i' ) AS time_group_by FROM ${item.datatablename} dv JOIN ( SELECT 1 AS currentTimeValid, LEAD(MIN(time), 1) OVER (ORDER BY time) IS NOT NULL AS leadTimeValid, MIN(time) AS minTime, MAX(time) AS maxTime, LAG(MAX(time), 1) OVER (ORDER BY time) AS lagMaxTime FROM ${item.datatablename} WHERE id_device = #{item.id} AND ( CASE WHEN #{start_date} IS NULL OR #{end_date} IS NULL THEN time BETWEEN CONVERT_TZ(DATE_FORMAT(CONVERT_TZ(DATE_SUB(UTC_TIMESTAMP(), INTERVAL 2 DAY), 'UTC', #{item.timezone_value}), '%Y-%m-%d 00:00:00'), #{item.timezone_value}, 'UTC') AND CONVERT_TZ(DATE_FORMAT(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value}), '%Y-%m-%d 23:59:59'), #{item.timezone_value}, 'UTC') ELSE time BETWEEN CONVERT_TZ(#{start_date}, #{item.timezone_value}, 'UTC') AND CONVERT_TZ(#{end_date}, #{item.timezone_value}, 'UTC') END ) AND error = 0 GROUP BY FROM_UNIXTIME(( UNIX_TIMESTAMP(CONVERT_TZ(time, 'UTC', #{item.timezone_value})) DIV 900 )* 900, '%Y-%m-%d %H:%i' ) ) m ON m.minTime = dv.time AND dv.id_device = #{item.id}
) d GROUP BY id_site, id_device_type, time ) d GROUP BY id_site, id_device_type

SELECT
IFNULL( ROUND(
IF( DATEDIFF(#{end_date}, #{start_date}) <= 5, m.${item.name},
)
m.${item.name}
, ${item.rounding_decimals} ), 'N/A' ) AS ${item.name}
AS time FROM ${datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone JOIN ( SELECT AS currentTimeValid, AS leadTimeValid, MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime, LAG(MAX(dv.time), 1) OVER (ORDER BY dv.time) AS lagMaxTime,
IF( DATEDIFF(#{end_date}, #{start_date}) <= 5, AVG(dv.nvmActivePower), NULL )
NULL
${item.aggregate_function}(dv.nvmActivePower)
(
AVG(CAST(dv.nvm_irradiance AS DECIMAL(10,4))) / 4
AVG(dv.nvm_irradiance) * 1
SELECT value / 1000 FROM (
) i WHERE i.time_group_by_interval =
NULL
)
(
SELECT value FROM (
) i WHERE i.time_group_by_interval =
NULL
)
${item.aggregate_function}(dv.${item.name})
AS ${item.name}
FROM ${datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE dv.id_device = #{id} AND dv.time BETWEEN CONVERT_TZ(#{start_date}, t.value, 'UTC') AND CONVERT_TZ(#{end_date}, t.value, 'UTC') AND dv.error = 0 GROUP BY
) m ON m.minTime = dv.time AND dv.id_device = #{id}
LIMIT #{limit}
OFFSET #{offset}
